function showLoginOverlay(){
  const overlay = document.getElementById('loginOverlay');
  const card = document.getElementById('loginCard');
  overlay.style.display = 'flex';
  const noPasswordsYet = !state.config.adminPasswordHash;

  if(noPasswordsYet){
    card.innerHTML = `
      <h2>Configura el acceso</h2>
      <p>Todavía no hay claves configuradas. Crea la clave de administrador (obligatoria) y, si quieres, la clave
      para usuario común ahora mismo.</p>
      <label>Clave de administrador (mínimo 4 caracteres)</label>
      <input type="password" id="loginNewAdmin" autocomplete="new-password">
      <label>Repetir clave de administrador</label>
      <input type="password" id="loginNewAdmin2" autocomplete="new-password">
      <label>Clave de usuario común (opcional por ahora)</label>
      <input type="password" id="loginNewUser" autocomplete="new-password">
      <button class="btn gold" id="loginSetupBtn" style="width:100%;margin-top:16px;">Crear y entrar como administrador</button>
      <div id="loginError"></div>
    `;
    document.getElementById('loginSetupBtn').addEventListener('click', async ()=>{
      const p1 = document.getElementById('loginNewAdmin').value;
      const p2 = document.getElementById('loginNewAdmin2').value;
      const pu = document.getElementById('loginNewUser').value;
      if(!p1 || p1.length < 4){ showToast('La clave de administrador debe tener al menos 4 caracteres', true); return; }
      if(p1 !== p2){ showToast('Las claves de administrador no coinciden', true); return; }
      const newCfg = { adminPasswordHash: await hashPassword(p1) };
      if(pu){
        if(pu.length < 4){ showToast('La clave de usuario común debe tener al menos 4 caracteres', true); return; }
        newCfg.userPasswordHash = await hashPassword(pu);
      }
      try{
        const result = await apiPostWithRetry({ type:'save_config', config: newCfg });
        state.config = Object.assign({}, state.config, result.config);
        sessionAdmin = true;
        sessionLoggedIn = true;
        document.getElementById('loginOverlay').style.display = 'none';
        renderRoleUI();
        renderStudents();
        showToast('Acceso configurado. Sesión de administrador iniciada.');
      }catch(e){
        showToast('No se pudo guardar la clave: ' + e.message, true);
      }
    });
  } else {
    card.innerHTML = `
      <h2>Ingresar a la plataforma</h2>
      <p>Ingresa tu clave. La clave de administrador da acceso completo; la clave de usuario común permite
      escanear, ver datos y agregar alumnos.</p>
      <label>Clave</label>
      <input type="password" id="loginPassword" autocomplete="current-password">
      <button class="btn gold" id="loginEnterBtn" style="width:100%;margin-top:16px;">Entrar</button>
      <div id="loginError"></div>
    `;
    const tryLogin = async ()=>{
      const pass = document.getElementById('loginPassword').value;
      const hash = await hashPassword(pass);
      if(hash === state.config.adminPasswordHash){
        sessionAdmin = true;
        sessionLoggedIn = true;
        document.getElementById('loginOverlay').style.display = 'none';
        renderRoleUI();
        renderStudents();
        showToast('Sesión de administrador iniciada');
      } else if(state.config.userPasswordHash && hash === state.config.userPasswordHash){
        sessionAdmin = false;
        sessionLoggedIn = true;
        document.getElementById('loginOverlay').style.display = 'none';
        renderRoleUI();
        renderStudents();
        showToast('Sesión de usuario común iniciada');
      } else {
        document.getElementById('loginError').innerHTML = '<div class="locked-note">Clave incorrecta. Intenta de nuevo.</div>';
      }
    };
    document.getElementById('loginEnterBtn').addEventListener('click', tryLogin);
    document.getElementById('loginPassword').addEventListener('keydown', (e)=>{ if(e.key === 'Enter') tryLogin(); });
  }
}

// ================= Utils =================
function cleanRut(rut){ return (rut || '').toString().toUpperCase().replace(/[.\-\s]/g,''); }
function formatRut(rut){
  const c = cleanRut(rut);
  if(c.length < 2) return c;
  const body = c.slice(0,-1);
  const dv = c.slice(-1);
  let out = '';
  for(let i=0;i<body.length;i++){
    const posFromEnd = body.length - i;
    out += body[i];
    if(posFromEnd > 1 && posFromEnd % 3 === 1) out += '.';
  }
  return out + '-' + dv;
}
function validarRut(rutSucio){
  const rut = cleanRut(rutSucio);
  if(!/^[0-9]+[0-9K]$/.test(rut)) return false;
  const body = rut.slice(0,-1);
  const dv = rut.slice(-1);
  let suma = 0, multiplo = 2;
  for(let i = body.length - 1; i >= 0; i--){
    suma += parseInt(body[i], 10) * multiplo;
    multiplo = multiplo === 7 ? 2 : multiplo + 1;
  }
  const resto = 11 - (suma % 11);
  let dvEsperado = resto === 11 ? '0' : (resto === 10 ? 'K' : String(resto));
  return dvEsperado === dv;
}
function todayStr(){ return new Date().toLocaleDateString('es-CL'); }
function dateStrDaysAgo(n){
  const d = new Date(); d.setDate(d.getDate() - n);
  return d.toLocaleDateString('es-CL');
}
function timeStr(){ return new Date().toLocaleTimeString('es-CL', {hour:'2-digit', minute:'2-digit'}); }
function uid(){ return Date.now().toString(36) + Math.random().toString(36).slice(2,8); }
function escapeHtml(str){
  return (str||'').toString().replace(/[&<>"']/g, c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));
}
function showToast(msg, isError){
  const root = document.getElementById('toastRoot');
  const t = document.createElement('div');
  t.className = 'toast';
  t.style.borderLeftColor = isError ? '#b3432b' : '#c9a227';
  t.textContent = msg;
  root.appendChild(t);
  setTimeout(()=>t.remove(), 3500);
}

