// ================= Alumnos =================
function renderStudents(){
  const list = document.getElementById('studentList');
  const q = (document.getElementById('studentSearch').value || '').toLowerCase();
  const filtered = state.students.filter(s=>{
    return !q || s.nombre.toLowerCase().includes(q) || cleanRut(s.rut).toLowerCase().includes(q.replace(/[.\-\s]/g,'')) || (s.curso||'').toLowerCase().includes(q);
  });
  if(filtered.length === 0){
    list.innerHTML = `<div class="empty">${state.students.length===0 ? 'Aún no hay alumnos. Agrega el primero con "+ Nuevo".' : 'Sin resultados.'}</div>`;
    return;
  }
  list.innerHTML = filtered.map(s=>`
    <div class="student-row">
      <div class="student-info">
        <b>${escapeHtml(s.nombre)}</b>
        <div>${formatRut(s.rut)} · ${escapeHtml(s.curso||'-')}</div>
        <div>Apoderado: ${escapeHtml(s.apoderadoNombre||'-')} · ${escapeHtml(s.apoderadoTelefono||'-')}</div>
        <div>
          ${s.apoderadoEmail ? '<span class="chip">✉️ Correo</span>' : ''}
          ${s.callmebotApiKey ? '<span class="chip">💬 WhatsApp</span>' : ''}
          ${(!s.apoderadoEmail && !s.callmebotApiKey) ? '<span class="chip">Solo registro</span>' : ''}
        </div>
      </div>
      <div class="row-actions">
        <button class="btn sm ghost" onclick="openQrModal('${s.rut}')">QR</button>
        ${sessionAdmin ? `<button class="btn sm ghost" onclick="openStudentModal('${s.rut}')">Editar</button>` : ''}
        ${sessionAdmin ? `<button class="btn sm danger" onclick="deleteStudent('${s.rut}')">Borrar</button>` : ''}
      </div>
    </div>
  `).join('');
}

document.getElementById('studentSearch').addEventListener('input', renderStudents);
document.getElementById('addStudentBtn').addEventListener('click', ()=>openStudentModal(null));

function openStudentModal(rut){
  const existing = rut ? state.students.find(s=>cleanRut(s.rut)===cleanRut(rut)) : null;
  if(existing && !sessionAdmin){
    showToast('Solo un administrador puede editar alumnos existentes', true);
    return;
  }
  const modalRoot = document.getElementById('modalRoot');
  modalRoot.innerHTML = `
    <div class="modal-bg" id="modalBg">
      <div class="modal">
        <h3 style="margin-top:0;color:var(--navy);">${existing ? 'Editar alumno' : 'Nuevo alumno'}</h3>
        <label>Nombre completo</label>
        <input type="text" id="f_nombre" value="${existing ? escapeHtml(existing.nombre) : ''}">
        <label>RUT del alumno</label>
        <input type="text" id="f_rut" placeholder="12345678-9" value="${existing ? existing.rut : ''}" ${existing ? 'disabled' : ''}>
        <div class="field-hint">Se valida automáticamente el dígito verificador antes de guardar.</div>
        <label>Curso</label>
        <input type="text" id="f_curso" placeholder="Ej: 3° Medio A" value="${existing ? escapeHtml(existing.curso||'') : ''}">
        <label>Nombre del apoderado</label>
        <input type="text" id="f_apName" value="${existing ? escapeHtml(existing.apoderadoNombre||'') : ''}">
        <label>Teléfono del apoderado</label>
        <input type="tel" id="f_apPhone" placeholder="+56912345678" value="${existing ? escapeHtml(existing.apoderadoTelefono||'') : ''}">
        <label>Correo del apoderado (opcional)</label>
        <input type="email" id="f_apEmail" placeholder="apoderado@correo.cl" value="${existing ? escapeHtml(existing.apoderadoEmail||'') : ''}">
        <label>CallMeBot API Key (opcional, WhatsApp gratuito)</label>
        <input type="text" id="f_apCmb" placeholder="Ej: 123456" value="${existing ? escapeHtml(existing.callmebotApiKey||'') : ''}">
        <div style="display:flex;gap:10px;margin-top:20px;">
          <button class="btn gold" id="saveStudentBtn" style="flex:1;">Guardar</button>
          <button class="btn ghost" id="cancelStudentBtn" style="flex:1;">Cancelar</button>
        </div>
      </div>
    </div>
  `;
  document.getElementById('cancelStudentBtn').addEventListener('click', closeModal);
  document.getElementById('modalBg').addEventListener('click', (e)=>{ if(e.target.id==='modalBg') closeModal(); });
  document.getElementById('saveStudentBtn').addEventListener('click', async ()=>{
    const nombre = document.getElementById('f_nombre').value.trim();
    const rutRaw = document.getElementById('f_rut').value.trim();
    const curso = document.getElementById('f_curso').value.trim();
    const apName = document.getElementById('f_apName').value.trim();
    const apPhone = document.getElementById('f_apPhone').value.trim();
    const apEmail = document.getElementById('f_apEmail').value.trim();
    const apCmb = document.getElementById('f_apCmb').value.trim();
    if(!nombre || !rutRaw){ showToast('Nombre y RUT son obligatorios', true); return; }
    const rutClean = cleanRut(rutRaw);
    if(!validarRut(rutClean)){ showToast('El RUT no es válido: revisa el dígito verificador', true); return; }
    if(!existing && state.students.some(s=>cleanRut(s.rut)===rutClean)){ showToast('Ya existe un alumno con ese RUT', true); return; }
    const datos = { rut: rutClean, nombre, curso, apoderadoNombre:apName, apoderadoTelefono:apPhone, apoderadoEmail:apEmail, callmebotApiKey:apCmb };
    try{
      if(existing){
        await apiPostWithRetry({ type:'update_student', student: datos });
        Object.assign(existing, datos);
      } else {
        await apiPostWithRetry({ type:'add_student', student: datos });
        state.students.push(datos);
      }
      renderStudents();
      closeModal();
      showToast(existing ? 'Alumno actualizado' : 'Alumno agregado');
    }catch(e){ showToast('No se pudo guardar: ' + e.message, true); }
  });
}

async function deleteStudent(rut){
  if(!sessionAdmin){ showToast('Solo un administrador puede borrar alumnos', true); return; }
  if(!confirm('¿Eliminar este alumno? Su historial de asistencia se conservará.')) return;
  try{
    await apiPostWithRetry({ type:'delete_student', rut });
    state.students = state.students.filter(s=>cleanRut(s.rut)!==cleanRut(rut));
    renderStudents();
    showToast('Alumno eliminado');
  }catch(e){ showToast('No se pudo borrar: ' + e.message, true); }
}

function openQrModal(rut){
  const s = state.students.find(x=>cleanRut(x.rut)===cleanRut(rut));
  if(!s) return;
  const modalRoot = document.getElementById('modalRoot');
  modalRoot.innerHTML = `
    <div class="modal-bg" id="modalBg">
      <div class="modal" style="text-align:center;">
        <h3 style="margin-top:0;color:var(--navy);">${escapeHtml(s.nombre)}</h3>
        <div style="color:#777;font-size:0.85rem;margin-bottom:10px;">${formatRut(s.rut)} · ${escapeHtml(s.curso||'')}</div>
        <div class="qr-print"><div id="qrCanvasBox"></div><div style="font-size:0.8rem;color:#666;">Código QR para el carné del alumno</div></div>
        <div style="display:flex;gap:10px;margin-top:16px;">
          <button class="btn gold" id="downloadQrBtn" style="flex:1;">Descargar</button>
          <button class="btn ghost" id="closeQrBtn" style="flex:1;">Cerrar</button>
        </div>
      </div>
    </div>
  `;
  const qr = qrcode(0, 'M');
  qr.addData(cleanRut(s.rut));
  qr.make();
  document.getElementById('qrCanvasBox').innerHTML = qr.createImgTag(6, 8);
  document.getElementById('closeQrBtn').addEventListener('click', closeModal);
  document.getElementById('modalBg').addEventListener('click', (e)=>{ if(e.target.id==='modalBg') closeModal(); });
  document.getElementById('downloadQrBtn').addEventListener('click', ()=>{
    const img = document.querySelector('#qrCanvasBox img');
    const link = document.createElement('a');
    link.download = `QR_${cleanRut(s.rut)}.gif`;
    link.href = img.src;
    link.click();
  });
}

function closeModal(){ document.getElementById('modalRoot').innerHTML = ''; }

// ================= Escáner =================
document.getElementById('modeCameraBtn').addEventListener('click', ()=>switchScanMode('camera'));
document.getElementById('modeUsbBtn').addEventListener('click', ()=>switchScanMode('usb'));

function switchScanMode(mode){
  scanMode = mode;
  document.getElementById('cameraPanel').style.display = mode === 'camera' ? 'block' : 'none';
  document.getElementById('usbPanel').style.display = mode === 'usb' ? 'block' : 'none';
  document.getElementById('modeCameraBtn').classList.toggle('gold', mode === 'camera');
  document.getElementById('modeCameraBtn').classList.toggle('ghost', mode !== 'camera');
  document.getElementById('modeUsbBtn').classList.toggle('gold', mode === 'usb');
  document.getElementById('modeUsbBtn').classList.toggle('ghost', mode !== 'usb');
  stopScanner();
  document.getElementById('scanResultArea').innerHTML = '';
  if(mode === 'usb') focusUsbInput();
}

function focusUsbInput(){
  const el = document.getElementById('usbInput');
  if(scanMode === 'usb' && document.getElementById('tab-scan').style.display !== 'none') el.focus();
}

const usbInput = document.getElementById('usbInput');
usbInput.addEventListener('keydown', (e)=>{
  if(e.key === 'Enter'){
    e.preventDefault();
    const value = usbInput.value.trim();
    usbInput.value = '';
    if(value) handleScan(value);
  }
});
usbInput.addEventListener('blur', ()=>{ setTimeout(focusUsbInput, 150); });
setInterval(focusUsbInput, 1500);

document.getElementById('startScanBtn').addEventListener('click', startScanner);
document.getElementById('stopScanBtn').addEventListener('click', stopScanner);

async function startScanner(){
  if(state.students.length === 0){ showToast('Primero agrega alumnos en la pestaña "Alumnos"', true); return; }
  try{
    stream = await navigator.mediaDevices.getUserMedia({ video: { facingMode: 'environment' } });
  }catch(e){
    showToast('No se pudo acceder a la cámara. Revisa los permisos.', true);
    return;
  }
  const video = document.getElementById('video');
  video.srcObject = stream;
  try{ await video.play(); }catch(e){}
  document.getElementById('scanFrame').style.display = 'block';
  document.getElementById('startScanBtn').style.display = 'none';
  document.getElementById('stopScanBtn').style.display = 'inline-block';
  scanning = true;
  const track = stream.getVideoTracks()[0];
  if(track){
    track.onended = () => {
      if(scanning){
        showToast('Se perdió la conexión con la cámara.', true);
        stopScanner();
      }
    };
  }
  scanLoop();
}

function stopScanner(){
  scanning = false;
  if(scanLoopHandle) cancelAnimationFrame(scanLoopHandle);
  if(stream){ stream.getTracks().forEach(t=>t.stop()); stream = null; }
  document.getElementById('scanFrame').style.display = 'none';
  document.getElementById('startScanBtn').style.display = 'inline-block';
  document.getElementById('stopScanBtn').style.display = 'none';
}

function scanLoop(){
  if(!scanning) return;
  try{
    const video = document.getElementById('video');
    const canvas = document.getElementById('canvas');
    if(video.readyState === video.HAVE_ENOUGH_DATA){
      canvas.width = video.videoWidth;
      canvas.height = video.videoHeight;
      const ctx = canvas.getContext('2d');
      ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
      const imageData = ctx.getImageData(0, 0, canvas.width, canvas.height);
      const code = jsQR(imageData.data, imageData.width, imageData.height, { inversionAttempts: 'attemptBoth' });
      if(code && code.data){
        if(code.data === pendingCode){ pendingCount++; } else { pendingCode = code.data; pendingCount = 1; }
        const now = Date.now();
        if(pendingCount >= 2 && now - lastScanTime > 2500){
          lastScanTime = now;
          pendingCount = 0;
          handleScan(code.data);
        }
      } else { pendingCode = null; pendingCount = 0; }
    }
  }catch(e){ console.error('Error leyendo un cuadro de la cámara:', e); }
  scanLoopHandle = requestAnimationFrame(scanLoop);
}

async function handleScan(rawValue){
  const rut = cleanRut(rawValue);
  const area = document.getElementById('scanResultArea');

  if(!validarRut(rut)){
    area.innerHTML = `<div class="result-card result-error"><div class="result-name">Código QR dañado o inválido</div>
      <div class="result-row"><span>Código leído</span><span>${escapeHtml(rawValue)}</span></div>
      <div class="result-row"><span></span><span>El dígito verificador no coincide. Reintenta escanear.</span></div></div>`;
    showToast('Código QR no válido, intenta de nuevo', true);
    return;
  }

  const student = state.students.find(s=>cleanRut(s.rut)===rut);
  if(!student){
    area.innerHTML = `<div class="result-card result-error"><div class="result-name">QR no reconocido</div>
      <div class="result-row"><span>RUT leído</span><span>${formatRut(rut)}</span></div>
      <div class="result-row"><span></span><span>No coincide con ningún alumno registrado</span></div></div>`;
    return;
  }

  const registroReciente = state.attendance.find(r =>
    cleanRut(r.rut) === rut && r.fecha === todayStr() && (Date.now() - Number(r.timestamp)) < 3 * 60 * 1000
  );
  if(registroReciente){
    area.innerHTML = `<div class="result-card" style="border-color:#c9a227;"><div class="result-name">${escapeHtml(student.nombre)}</div>
      <div class="result-row"><span></span><span>Ya se registró su asistencia hoy a las ${registroReciente.hora}</span></div>
      <div class="result-badge">Registro duplicado evitado</div></div>`;
    showToast(`${student.nombre} ya fue registrado a las ${registroReciente.hora}`);
    return;
  }

  const canal = [];
  const mensaje = `${student.nombre} registró su ingreso al colegio a las ${timeStr()} del ${todayStr()}.`;

  if(student.apoderadoEmail){
    try{
      await apiPost({ type:'notify_guardian', email: student.apoderadoEmail, nombre: student.nombre, mensaje });
      canal.push('correo');
    }catch(e){ /* seguimos igual, la asistencia se registra de todas formas */ }
  }
  if(student.callmebotApiKey){
    sendCallMeBot(student.apoderadoTelefono, student.callmebotApiKey, mensaje);
    canal.push('whatsapp');
  }
  if(canal.length === 0) canal.push('simulado');

  const record = {
    id: uid(), rut: student.rut, nombre: student.nombre, curso: student.curso,
    fecha: todayStr(), hora: timeStr(), timestamp: Date.now(), canal: canal.join(', ')
  };
  state.attendance.unshift(record);
  renderHistory();
  apiPostWithRetry({ type:'add_attendance', record }).catch(()=>{});

  const badges = canal.map(c=>{
    if(c==='correo') return '<span class="result-badge">✉️ Correo enviado</span>';
    if(c==='whatsapp') return '<span class="result-badge">💬 WhatsApp enviado</span>';
    return '<span class="result-badge">Solo registrado (sin canal configurado)</span>';
  }).join('');

  area.innerHTML = `<div class="result-card"><div class="result-name">${escapeHtml(student.nombre)}</div>
    <div class="result-row"><span>Curso</span><span>${escapeHtml(student.curso||'-')}</span></div>
    <div class="result-row"><span>Fecha</span><span>${record.fecha}</span></div>
    <div class="result-row"><span>Hora</span><span>${record.hora}</span></div>
    <div style="margin-top:12px;">${badges}</div></div>`;

  showToast(canal.includes('simulado')
    ? `Registrado. Sin correo/WhatsApp configurado para ${student.nombre}.`
    : `Notificación enviada al apoderado de ${student.nombre}.`);
}

// ================= Historial =================
function renderHistory(){
  const tbody = document.querySelector('#historyTable tbody');
  const q = (document.getElementById('historySearch').value || '').toLowerCase();
  const filtered = state.attendance.filter(r=>{
    return !q || r.nombre.toLowerCase().includes(q) || cleanRut(r.rut).toLowerCase().includes(q.replace(/[.\-\s]/g,'')) || (r.curso||'').toLowerCase().includes(q);
  });
  if(filtered.length === 0){
    tbody.innerHTML = `<tr><td colspan="5" class="empty">${state.attendance.length===0 ? 'Aún no hay registros de asistencia.' : 'Sin resultados.'}</td></tr>`;
  } else {
    tbody.innerHTML = filtered.map(r=>`
      <tr><td>${escapeHtml(r.nombre)}</td><td>${escapeHtml(r.curso||'-')}</td><td>${r.fecha}</td><td>${r.hora}</td><td>${r.canal||'simulado'}</td></tr>
    `).join('');
  }
  document.getElementById('statTotal').textContent = state.attendance.length;
  document.getElementById('statToday').textContent = state.attendance.filter(r=>r.fecha===todayStr()).length;
}
document.getElementById('historySearch').addEventListener('input', renderHistory);

document.getElementById('exportBtn').addEventListener('click', ()=>{
  if(state.attendance.length === 0){ showToast('No hay registros para exportar', true); return; }
  const rows = state.attendance.map(r=>({
    Nombre: r.nombre, RUT: formatRut(r.rut), Curso: r.curso || '', Fecha: r.fecha, Hora: r.hora,
    Notificacion: r.canal || 'simulado'
  }));
  const ws = XLSX.utils.json_to_sheet(rows);
  const wb = XLSX.utils.book_new();
  XLSX.utils.book_append_sheet(wb, ws, 'Asistencia');
  XLSX.writeFile(wb, `asistencia_${todayStr().replace(/\//g,'-')}.xlsx`);
});

// ================= Estadísticas =================
function renderStats(){
  const hoy = todayStr();
  const porCurso = {};
  state.attendance.filter(r=>r.fecha===hoy).forEach(r=>{
    const c = r.curso || 'Sin curso';
    porCurso[c] = (porCurso[c]||0) + 1;
  });
  const cursoLabels = Object.keys(porCurso);
  const cursoValues = cursoLabels.map(k=>porCurso[k]);

  const dias = [];
  for(let i=6;i>=0;i--) dias.push(dateStrDaysAgo(i));
  const conteoPorDia = dias.map(d=>state.attendance.filter(r=>r.fecha===d).length);

  const ctx1 = document.getElementById('chartCurso').getContext('2d');
  if(chartCurso) chartCurso.destroy();
  chartCurso = new Chart(ctx1, {
    type: 'bar',
    data: { labels: cursoLabels.length ? cursoLabels : ['Sin registros hoy'], datasets: [{ label:'Registros', data: cursoValues.length ? cursoValues : [0], backgroundColor:'#0b2545', borderRadius:6 }] },
    options: { responsive:true, maintainAspectRatio:false, plugins:{legend:{display:false}}, scales:{ y:{ beginAtZero:true, ticks:{ precision:0 } } } }
  });

  const ctx2 = document.getElementById('chartSemana').getContext('2d');
  if(chartSemana) chartSemana.destroy();
  chartSemana = new Chart(ctx2, {
    type: 'line',
    data: { labels: dias, datasets: [{ label:'Registros por día', data: conteoPorDia, borderColor:'#c9a227', backgroundColor:'rgba(201,162,39,0.15)', tension:0.3, fill:true, pointBackgroundColor:'#0b2545' }] },
    options: { responsive:true, maintainAspectRatio:false, plugins:{legend:{display:false}}, scales:{ y:{ beginAtZero:true, ticks:{ precision:0 } } } }
  });
}

// ================= Sincronización periódica (casi en tiempo real) =================
function startPolling(){
  setInterval(async ()=>{
    if(pendingSaves > 0 || isModalOpen() || !sessionLoggedIn) return;
    try{
      const data = await apiGet();
      state.config = Object.assign({}, state.config, data.config || {});
      state.students = data.students || [];
      state.attendance = data.attendance || [];
      lastSyncFailed = false;
      renderHeader();
      renderStudents();
      renderHistory();
      const statsTab = document.getElementById('tab-stats');
      if(statsTab && statsTab.style.display !== 'none') renderStats();
    }catch(e){
      lastSyncFailed = true;
    }
    updateSyncIndicator();
  }, 7000);
}

